-- Declare PRIMARY KEY on dimension tables to enable join elimination
-- These constraints are informational — Delta does not enforce them
-- but Catalyst uses them for plan optimization

ALTER TABLE dim_regions ADD CONSTRAINT pk_regions PRIMARY KEY (region_code);
ALTER TABLE dim_substations ADD CONSTRAINT pk_subs PRIMARY KEY (substation_id);
ALTER TABLE dim_tariff_codes ADD CONSTRAINT pk_tariffs PRIMARY KEY (tariff_code);

