// Exactly-once verification: compare Event Hub input count to KQL ingestion count
// Run daily as a scheduled KQL query

let eh_count = external_table('EventHubMetrics')
    | where MetricName == 'IncomingMessages' and TimeGenerated > ago(24h)
    | summarize total_eh_events = sum(Total) by bin(TimeGenerated, 1h);

let kql_count = ScadaTelemetry
    | where ingestion_time() > ago(24h)
    | summarize total_kql_events = count() by bin(ingestion_time(), 1h);

eh_count
| join kind=inner kql_count on $left.TimeGenerated == $right.ingestion_time
| extend delta = total_eh_events - total_kql_events
| extend delta_pct = round(100.0 * delta / total_eh_events, 2)
| where abs(delta_pct) > 0.1  // Flag if >0.1% discrepancy
| project TimeGenerated, total_eh_events, total_kql_events, delta, delta_pct

// Materialized view: per-turbine hourly aggregation for the operations dashboard
// Pre-computes what the dashboard queries every 30 seconds
// Without MV: dashboard scans 172M events/day × 7 days = 1.2B rows per query
// With MV: dashboard reads pre-computed hourly summaries = 3.4M rows per query (350x reduction)

.create materialized-view with (backfill=true)
TurbineHourlySummary on table ScadaTelemetry {
    ScadaTelemetry
    | summarize 
        avg_temperature = avg(temperature),
        max_temperature = max(temperature),
        avg_rpm = avg(rpm),
        total_power_kwh = sum(power_output) / 360,  // 10-sec intervals to kWh
        event_count = count(),
        anomaly_count = countif(temperature > 85.0)
    by turbine_id, country, grid_zone, bin(timestamp, 1h)
}

# GridUnion's multi-capacity 12-month projection model
# Runs quarterly and feeds into the annual budget request

capacities = {
    "F128_DE_NL_eng": {
        "current_peak_pct": 58,
        "growth_rate_monthly": 1.5,  # 1.5% per month (data volume growth)
        "planned_additions": [
            {"month": 4, "description": "New Dutch wind farm (500 turbines)", "impact_pct": 5},
            {"month": 8, "description": "BNetzA grid zone reporting", "impact_pct": 3},
        ],
        "optimization_pipeline": [
            {"month": 3, "description": "Silver partition optimization", "savings_pct": 4},
        ]
    },
    "F64_FR_LU_eng": {"current_peak_pct": 45, "growth_rate_monthly": 2.0, "planned_additions": [], "optimization_pipeline": []},
    "F64_analytics": {"current_peak_pct": 52, "growth_rate_monthly": 3.0, "planned_additions": [
        {"month": 6, "description": "2 new analytics teams onboarded", "impact_pct": 15}
    ], "optimization_pipeline": []},
    "F32_streaming": {"current_peak_pct": 35, "growth_rate_monthly": 1.0, "planned_additions": [], "optimization_pipeline": []},
}

for name, cap in capacities.items():
    peak = cap["current_peak_pct"]
    for month in range(1, 13):
        peak *= (1 + cap["growth_rate_monthly"] / 100)
        for add in cap["planned_additions"]:
            if add["month"] == month: peak += add["impact_pct"]
        for opt in cap["optimization_pipeline"]:
            if opt["month"] == month: peak -= opt["savings_pct"]
    months_to_70 = None
    p = cap["current_peak_pct"]
    for m in range(1, 25):
        p *= (1 + cap["growth_rate_monthly"] / 100)
        for add in cap["planned_additions"]:
            if add["month"] == m: p += add["impact_pct"]
        for opt in cap["optimization_pipeline"]:
            if opt["month"] == m: p -= opt["savings_pct"]
        if p >= 70 and months_to_70 is None: months_to_70 = m
    print(f"{name}: 12-month peak={peak:.0f}%, months to 70%={months_to_70 or '>24'}")
